CREATE TABLE "auth_group" ("id" serial PRIMARY KEY , "name" varchar(150) NOT NULL UNIQUE);
CREATE TABLE "auth_group_permissions" ("id" serial PRIMARY KEY , "group_id" integer NOT NULL REFERENCES "auth_group" ("id") DEFERRABLE INITIALLY DEFERRED, "permission_id" integer NOT NULL REFERENCES "auth_permission" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "auth_permission" ("id" serial PRIMARY KEY , "content_type_id" integer NOT NULL REFERENCES "django_content_type" ("id") DEFERRABLE INITIALLY DEFERRED, "codename" varchar(100) NOT NULL, "name" varchar(255) NOT NULL);
CREATE TABLE "django_admin_log" ("id" serial PRIMARY KEY , "object_id" text NULL, "object_repr" varchar(200) NOT NULL, "action_flag" smallint  NOT NULL CHECK ("action_flag" >= 0), "change_message" text NOT NULL, "content_type_id" integer NULL REFERENCES "django_content_type" ("id") DEFERRABLE INITIALLY DEFERRED, "user_id" bigint NOT NULL REFERENCES "users_user" ("id") DEFERRABLE INITIALLY DEFERRED, "action_time" timestamp with time zone NOT NULL);
CREATE TABLE "django_content_type" ("id" serial PRIMARY KEY , "app_label" varchar(100) NOT NULL, "model" varchar(100) NOT NULL);
CREATE TABLE "django_migrations" ("id" serial PRIMARY KEY , "app" varchar(255) NOT NULL, "name" varchar(255) NOT NULL, "applied" timestamp with time zone NOT NULL);
CREATE TABLE "django_session" ("session_key" varchar(40) NOT NULL PRIMARY KEY, "session_data" text NOT NULL, "expire_date" timestamp with time zone NOT NULL);
CREATE TABLE "exams_attempt" ("id" serial PRIMARY KEY , "attempt_number" integer NOT NULL, "counts_for_score" boolean NOT NULL, "status" varchar(20) NOT NULL, "score_obtained" integer NOT NULL, "started_at" timestamp with time zone NOT NULL, "last_activity_at" timestamp with time zone NOT NULL, "completed_at" timestamp with time zone NULL, "user_id" bigint NOT NULL REFERENCES "users_user" ("id") DEFERRABLE INITIALLY DEFERRED, "exam_id" bigint NOT NULL REFERENCES "exams_exam" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "exams_attemptanswer" ("id" serial PRIMARY KEY , "is_correct" boolean NOT NULL, "points_obtained" integer NOT NULL, "answered_at" timestamp with time zone NOT NULL, "attempt_id" bigint NOT NULL REFERENCES "exams_attempt" ("id") DEFERRABLE INITIALLY DEFERRED, "question_id" bigint NOT NULL REFERENCES "exams_question" ("id") DEFERRABLE INITIALLY DEFERRED, "selected_option_id" bigint NULL REFERENCES "exams_option" ("id") DEFERRABLE INITIALLY DEFERRED, "text_response" text NULL);
CREATE TABLE "exams_attemptanswer_selected_options" ("id" serial PRIMARY KEY , "attemptanswer_id" bigint NOT NULL REFERENCES "exams_attemptanswer" ("id") DEFERRABLE INITIALLY DEFERRED, "option_id" bigint NOT NULL REFERENCES "exams_option" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "exams_attemptquestion" ("id" serial PRIMARY KEY , "order_number" integer NOT NULL, "attempt_id" bigint NOT NULL REFERENCES "exams_attempt" ("id") DEFERRABLE INITIALLY DEFERRED, "question_id" bigint NOT NULL REFERENCES "exams_question" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "exams_exam" ("id" serial PRIMARY KEY , "name" varchar(200) NOT NULL, "description" text NOT NULL, "bank_total_questions" integer NOT NULL, "questions_per_attempt" integer NOT NULL, "max_scored_attempts" integer NOT NULL, "max_points" integer NOT NULL, "is_active" boolean NOT NULL, "created_at" timestamp with time zone NOT NULL, "is_enabled" boolean NOT NULL);
CREATE TABLE "exams_option" ("id" serial PRIMARY KEY , "text" varchar(255) NOT NULL, "is_correct" boolean NOT NULL, "question_id" bigint NOT NULL REFERENCES "exams_question" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "exams_question" ("id" serial PRIMARY KEY , "text" text NOT NULL, "image" varchar(100) NULL, "points" integer NOT NULL, "time_limit_seconds" integer NOT NULL, "exam_id" bigint NOT NULL REFERENCES "exams_exam" ("id") DEFERRABLE INITIALLY DEFERRED, "question_type" varchar(20) NOT NULL);
CREATE TABLE "users_rank" ("id" serial PRIMARY KEY , "name" varchar(50) NOT NULL, "min_score" integer NOT NULL, "max_score" integer NOT NULL, "description" text NOT NULL, "badge_image" varchar(100) NULL);
CREATE TABLE "users_user" ("id" serial PRIMARY KEY , "password" varchar(128) NOT NULL, "last_login" timestamp with time zone NULL, "is_superuser" boolean NOT NULL, "username" varchar(150) NOT NULL UNIQUE, "first_name" varchar(150) NOT NULL, "last_name" varchar(150) NOT NULL, "email" varchar(254) NOT NULL, "is_staff" boolean NOT NULL, "is_active" boolean NOT NULL, "date_joined" timestamp with time zone NOT NULL, "total_score" integer NOT NULL, "current_rank_id" bigint NULL REFERENCES "users_rank" ("id") DEFERRABLE INITIALLY DEFERRED, "dni" varchar(20) NOT NULL);
CREATE TABLE "users_user_groups" ("id" serial PRIMARY KEY , "user_id" bigint NOT NULL REFERENCES "users_user" ("id") DEFERRABLE INITIALLY DEFERRED, "group_id" integer NOT NULL REFERENCES "auth_group" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "users_user_user_permissions" ("id" serial PRIMARY KEY , "user_id" bigint NOT NULL REFERENCES "users_user" ("id") DEFERRABLE INITIALLY DEFERRED, "permission_id" integer NOT NULL REFERENCES "auth_permission" ("id") DEFERRABLE INITIALLY DEFERRED);
